const inputJson = $input.first().json;
const payload = inputJson.body ?? inputJson;

const started_at = Date.now();
const timestamp = new Date(started_at).toISOString();
const trace_id = `trace_${started_at}_${Math.random().toString(36).slice(2, 10)}`;

const message = payload.message == null ? "" : String(payload.message).trim();

if (!message) {
  return [
    {
      json: {
        ok: false,
        error: "missing_message",
      },
    },
  ];
}

const history = Array.isArray(payload.history)
  ? payload.history.slice(-20)
  : [];

return [
  {
    json: {
      ok: true,
      trace_id,
      started_at,
      timestamp,
      session_id: payload.session_id,
      student_id: payload.student_id,
      course_id: payload.course_id,
      nickname: payload.nickname,
      message: message.slice(0, 500),
      history,
      citation_parse_failed: payload.citation_parse_failed,
    },
  },
];

const previous = $input.first().json;

if (previous.ok === false) {
  return [
    {
      json: {
        ...previous,
        model: "openai/gpt-5.5",
        openrouter_body: null,
      },
    },
  ];
}

const model = previous.primary_model || "openai/gpt-5.5";
const temperature = previous.safety_critical || previous.prompt_injection_risk ? 0.1 : 0.2;
const max_tokens = previous.model_strategy === "simple_fast" ? 650 : 900;

const history = Array.isArray(previous.history)
  ? previous.history.slice(-20)
  : [];

const system_prompt = `
You are LAS Foreman AI Tutor.

Persona:
- You are a Thai foreman tutor.
- Answer in Thai.
- Use "ครับ" only as the polite particle.
- Be practical, clear, and suitable for construction site supervision.

Safety rules:
- Do not invent numbers, specifications, dimensions, quantities, tolerances, codes, or approval status.
- If the knowledge base context is insufficient, say clearly that the information is insufficient.
- Do not approve work on behalf of PM, CM, Designer, Consultant, Owner, or Authority.
- Escalate questions involving fire-rated systems, structural issues, safety risks, variation orders, NCR, specification substitutions, or unclear design conflicts.
- If escalation is needed, include this exact line:
ESCALATE: <reason>

Citation rule:
- Your final line must be exactly in this format:
*(📚 ข้อมูล: XX% | 🎯 มั่นใจ: YY% | 🔗 Ref: <doc_id>)*
- Replace XX and YY with percentage numbers.
- Replace <doc_id> with the most relevant reference id.
- Do not add anything after the citation line.
`.trim();

const kb_context = `
MVP KB Context:

[doc_id: KB-RFI-001]
RFI is used when site teams need clarification because drawings, specifications, BOQ, or site conditions are unclear. Foreman should prepare the issue clearly with location, drawing/spec reference, photos if available, and proposed question before sending to PM/CM/Designer.

[doc_id: KB-CONFLICT-001]
If BOQ, Specification, and Drawing conflict, the foreman should not decide the final requirement alone. The issue should be raised to PM/CM/Designer for confirmation. Work should follow the officially clarified instruction.

[doc_id: KB-ESCALATION-001]
Escalation matrix: fire-rated work, structural work, safety issues, VO, NCR, material/spec substitution, and major drawing/spec conflicts must be escalated to PM/CM/Designer/Consultant as appropriate.

[doc_id: KB-FOREMAN-001]
When uncertain, the foreman should ask PM, CM, or Designer before proceeding, especially where quality, safety, cost, schedule, or compliance may be affected.
`.trim();

const conversation_history = history
  .map((item, index) => {
    const role = item.role || item.sender || "unknown";
    const content = item.content || item.message || "";
    return `${index + 1}. ${role}: ${content}`;
  })
  .join("\n");

const user_prompt = `
KB Context:
${kb_context}

Conversation history:
${conversation_history || "(no previous history)"}

Current user message:
${previous.message}

Metadata:
- session_id: ${previous.session_id || ""}
- student_id: ${previous.student_id || ""}
- course_id: ${previous.course_id || ""}
- nickname: ${previous.nickname || ""}
- citation_parse_failed: ${previous.citation_parse_failed === true ? "true" : "false"}
- model_strategy: ${previous.model_strategy || ""}
- model_selection_reason: ${previous.model_selection_reason || ""}

Answer the current user message using the KB context and safety rules.
`.trim();

const messages = [
  {
    role: "system",
    content: system_prompt,
  },
  {
    role: "user",
    content: user_prompt,
  },
];

return [
  {
    json: {
      ...previous,
      model,
      model_strategy: previous.model_strategy || "standard_quality",
      model_selection_reason: previous.model_selection_reason || "",
      safety_critical: previous.safety_critical === true,
      primary_model: previous.primary_model || model,
      fallback_model: previous.fallback_model || "openai/gpt-5.5",
      openrouter_body: {
        model,
        messages,
        temperature,
        max_tokens,
      },
    },
  },
];

const input = $input.first().json;
const original = $('Build Prompt').first().json;

let fallbackRequest = {};
try {
  fallbackRequest = $('Build Fallback Request').first().json;
} catch (error) {
  fallbackRequest = {};
}

const now = Date.now();

const trace_id = input.trace_id || fallbackRequest.trace_id || original.trace_id || "";
const started_at = Number(input.started_at || fallbackRequest.started_at || original.started_at || now);
const timestamp = input.timestamp || fallbackRequest.timestamp || original.timestamp || new Date(now).toISOString();

const session_id = input.session_id || fallbackRequest.session_id || original.session_id || "";
const student_id = input.student_id || fallbackRequest.student_id || original.student_id || "";
const course_id = input.course_id || fallbackRequest.course_id || original.course_id || "";
const nickname = input.nickname || fallbackRequest.nickname || original.nickname || "";
const question = input.message || fallbackRequest.message || original.message || "";

const fallback_used =
  input.fallback_used === true ||
  fallbackRequest.fallback_used === true ||
  original.fallback_used === true ||
  false;

const primary_error =
  input.primary_error ||
  fallbackRequest.primary_error ||
  original.primary_error ||
  "";

const model_strategy =
  input.model_strategy ||
  fallbackRequest.model_strategy ||
  original.model_strategy ||
  "standard_quality";

const safety_critical =
  input.safety_critical === true ||
  fallbackRequest.safety_critical === true ||
  original.safety_critical === true ||
  false;

const model_selection_reason =
  input.model_selection_reason ||
  fallbackRequest.model_selection_reason ||
  original.model_selection_reason ||
  "";

const model =
  input.model ||
  input.body?.model ||
  input.data?.model ||
  (fallback_used ? (fallbackRequest.fallback_model || original.fallback_model) : original.model) ||
  "";

const response_time_ms = now - started_at;

const usage =
  input.usage ||
  input.body?.usage ||
  input.data?.usage ||
  {};

const usage_prompt_tokens = usage.prompt_tokens ?? usage.promptTokens ?? null;
const usage_completion_tokens = usage.completion_tokens ?? usage.completionTokens ?? null;
const usage_total_tokens = usage.total_tokens ?? usage.totalTokens ?? null;
const response_cost =
  usage.cost ??
  input.cost ??
  input.body?.cost ??
  input.data?.cost ??
  null;

const openrouterError =
  input.error ||
  input.body?.error ||
  input.data?.error ||
  input.message?.error ||
  null;

const safeErrorAnswer = openrouterError
  ? "\u0e23\u0e30\u0e1a\u0e1a AI \u0e02\u0e31\u0e14\u0e02\u0e49\u0e2d\u0e07\u0e0a\u0e31\u0e48\u0e27\u0e04\u0e23\u0e32\u0e27\u0e04\u0e23\u0e31\u0e1a \u0e01\u0e23\u0e38\u0e13\u0e32\u0e25\u0e2d\u0e07\u0e43\u0e2b\u0e21\u0e48\u0e2d\u0e35\u0e01\u0e04\u0e23\u0e31\u0e49\u0e07 \u0e2b\u0e23\u0e37\u0e2d\u0e41\u0e08\u0e49\u0e07 Trainer \u0e43\u0e2b\u0e49\u0e0a\u0e48\u0e27\u0e22\u0e15\u0e23\u0e27\u0e08\u0e2a\u0e2d\u0e1a\u0e04\u0e23\u0e31\u0e1a"
  : "\u0e23\u0e30\u0e1a\u0e1a\u0e02\u0e31\u0e14\u0e02\u0e49\u0e2d\u0e07\u0e0a\u0e31\u0e48\u0e27\u0e04\u0e23\u0e32\u0e27\u0e04\u0e23\u0e31\u0e1a \u0e01\u0e23\u0e38\u0e13\u0e32\u0e25\u0e2d\u0e07\u0e43\u0e2b\u0e21\u0e48\u0e2d\u0e35\u0e01\u0e04\u0e23\u0e31\u0e49\u0e07";

const escalationFallbackAnswer =
  "\u0e02\u0e2d\u0e2a\u0e48\u0e07\u0e15\u0e48\u0e2d\u0e43\u0e2b\u0e49\u0e27\u0e34\u0e28\u0e27\u0e01\u0e23\u0e2b\u0e23\u0e37\u0e2d Trainer \u0e15\u0e23\u0e27\u0e08\u0e2a\u0e2d\u0e1a\u0e01\u0e48\u0e2d\u0e19\u0e04\u0e23\u0e31\u0e1a \u0e40\u0e1e\u0e23\u0e32\u0e30\u0e40\u0e23\u0e37\u0e48\u0e2d\u0e07\u0e19\u0e35\u0e49\u0e2d\u0e22\u0e39\u0e48\u0e19\u0e2d\u0e01\u0e02\u0e2d\u0e1a\u0e40\u0e02\u0e15\u0e17\u0e35\u0e48\u0e1c\u0e21\u0e22\u0e37\u0e19\u0e22\u0e31\u0e19\u0e44\u0e14\u0e49";

const rawAnswer =
  input.choices?.[0]?.message?.content ||
  input.body?.choices?.[0]?.message?.content ||
  input.data?.choices?.[0]?.message?.content ||
  "";

function buildOutput({
  answer,
  kb_relevance,
  confidence,
  doc_id,
  escalate,
  escalate_reason,
  citation_parse_failed,
}) {
  const safeAnswer = String(answer || "").trim() || (escalate ? escalationFallbackAnswer : safeErrorAnswer);

  const frontend_response = {
    answer: safeAnswer,
    kb_relevance,
    confidence,
    doc_id,
    escalate,
    escalate_reason,
    model,
    trace_id,
  };

  const sheet_log_payload = {
    timestamp,
    trace_id,
    session_id,
    student_id,
    course_id,
    nickname,
    question,
    answer: safeAnswer,
    response_time_ms,
    kb_relevance,
    confidence,
    doc_id,
    model,
    escalated: escalate,
    escalate_reason,
    citation_parse_failed,
    fallback_used,
    primary_error: primary_error ? String(primary_error).slice(0, 1000) : "",
    model_strategy,
    model_selection_reason,
    safety_critical,
    usage_prompt_tokens,
    usage_completion_tokens,
    usage_total_tokens,
    response_cost,
    feedback_type: "",
  };

  return [
    {
      json: {
        ...frontend_response,
        sheet_log_payload,
        frontend_response,
      },
    },
  ];
}

if (!rawAnswer) {
  return buildOutput({
    answer: safeErrorAnswer,
    kb_relevance: 0,
    confidence: 0,
    doc_id: openrouterError ? "openrouter_error" : "system_error",
    escalate: Boolean(openrouterError),
    escalate_reason: openrouterError
      ? "OpenRouter request failed or returned no usable answer"
      : "",
    citation_parse_failed: true,
  });
}

let answer = String(rawAnswer).trim();

const citationRegex = new RegExp("\\*\\(\\uD83D\\uDCDA \\u0e02\\u0e49\\u0e2d\\u0e21\\u0e39\\u0e25: (\\d+)% \\| \\uD83C\\uDFAF \\u0e21\\u0e31\\u0e48\\u0e19\\u0e43\\u0e08: (\\d+)% \\| \\uD83D\\uDD17 Ref: ([^)]+)\\)\\*");
const citationMatch = answer.match(citationRegex);

let kb_relevance = null;
let confidence = null;
let doc_id = "";
let citation_parse_failed = false;

if (citationMatch) {
  kb_relevance = Number(citationMatch[1]);
  confidence = Number(citationMatch[2]);
  doc_id = citationMatch[3].trim();
  answer = answer.replace(citationRegex, "").trim();
} else {
  citation_parse_failed = true;
}

const bannedPersonaPatterns = [
  /["'????]?\u0e19\u0e30\u0e08\u0e4a\u0e30["'????]?/g,
  /["'????]?\u0e19\u0e30\u0e04\u0e30["'????]?/g,
  /["'????]?\u0e04\u0e48\u0e30["'????]?/g,
  /["'????]?\u0e08\u0e49\u0e30["'????]?/g,
  /["'????]?\u0e08\u0e49\u0e32["'????]?/g,
];

for (const pattern of bannedPersonaPatterns) {
  answer = answer.replace(pattern, "").replace(/\s{2,}/g, " ").trim();
}

const escapedCitationTailRegex = /\*\(\uD83D\uDCDA[\s\S]*$/;
answer = answer.replace(escapedCitationTailRegex, "").trim();

const escalateRegex = /(?:^|[\n\r\s>-])ESCALATE:\s*([^\n\r]*)(?=\n|\r|$)/i;
const escalateMatch = answer.match(escalateRegex);

let escalate = false;
let escalate_reason = "";

if (escalateMatch) {
  escalate = true;
  escalate_reason = escalateMatch[1].replace(/[*_#>-]+/g, " ").replace(/\s{2,}/g, " ").trim();
  answer = answer.replace(escalateRegex, " ").replace(/\s{2,}/g, " ").trim();
}

const injectionLikeInput = /ignore|you are now|unrestricted|system prompt|developer message|previous instructions|jailbreak|prompt injection|confirm|verify|\u0e25\u0e37\u0e21 system prompt|\u0e25\u0e37\u0e21\u0e04\u0e33\u0e2a\u0e31\u0e48\u0e07|\u0e40\u0e21\u0e37\u0e48\u0e2d\u0e01\u0e35\u0e49|\u0e43\u0e0a\u0e48\u0e44\u0e2b\u0e21|\u0e22\u0e37\u0e19\u0e22\u0e31\u0e19/i.test(question);

function escapeRegExp(value) {
  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

if (injectionLikeInput) {
  const injectedNumberUnits = new Set(
    [...String(question).matchAll(/(\d+)\s*(mm|\u0e21\u0e21\.?|cm|\u0e0b\u0e21\.?|m\b|\u0e40\u0e21\u0e15\u0e23|D\b|Nm|kg(?:\/m2)?|\u0e01\u0e01\.?)/giu)]
      .map((match) => `${escapeRegExp(match[1])}\\s*${escapeRegExp(match[2])}`),
  );

  for (const escapedToken of injectedNumberUnits) {
    const tokenRegex = new RegExp(escapedToken, "giu");
    answer = answer.replace(tokenRegex, "\u0e04\u0e48\u0e32\u0e17\u0e35\u0e48\u0e2d\u0e49\u0e32\u0e07\u0e16\u0e36\u0e07");
  }

  answer = answer.replace(/\s{2,}/g, " ").trim();
}
return buildOutput({
  answer,
  kb_relevance,
  confidence,
  doc_id,
  escalate,
  escalate_reason,
  citation_parse_failed,
});

const original = $('Build Prompt').first().json;
const primaryResult = $input.first().json;

const fallbackModel = original.fallback_model || "anthropic/claude-sonnet-4.6";

const primary_error =
  primaryResult.error ||
  primaryResult.body?.error ||
  primaryResult.data?.error ||
  primaryResult.message ||
  "Primary model returned no usable answer";

return [
  {
    json: {
      ...original,
      model: fallbackModel,
      fallback_used: true,
      primary_error,
      model_strategy: original.model_strategy || "standard_quality",
      model_selection_reason: original.model_selection_reason || "",
      safety_critical: original.safety_critical === true,
      fallback_model: fallbackModel,
      openrouter_body: {
        ...original.openrouter_body,
        model: fallbackModel,
      },
    },
  },
];

const input = $input.first().json;

const now = Date.now();
const windowMs = 3000;

const key = [
  input.session_id || "anonymous_session",
  input.student_id || "anonymous_student",
].join(":");

const staticData = $getWorkflowStaticData("global");
staticData.crefulRateLimitStore = staticData.crefulRateLimitStore || {};

const lastSeen = Number(staticData.crefulRateLimitStore[key] || 0);
const elapsed = now - lastSeen;

staticData.crefulRateLimitStore[key] = now;

for (const [storeKey, timestamp] of Object.entries(staticData.crefulRateLimitStore)) {
  if (now - Number(timestamp) > 10 * 60 * 1000) {
    delete staticData.crefulRateLimitStore[storeKey];
  }
}

if (elapsed > 0 && elapsed < windowMs) {
  const retryAfterMs = windowMs - elapsed;

  return [
    {
      json: {
        ...input,
        ok: false,
        rate_limited: true,
        retry_after_ms: retryAfterMs,
      },
    },
  ];
}

return [
  {
    json: {
      ...input,
      rate_limited: false,
      retry_after_ms: 0,
    },
  },
];

const input = $input.first().json;

const now = Date.now();
const retrySeconds = Math.max(1, Math.ceil(Number(input.retry_after_ms || 0) / 1000));

const trace_id =
  input.trace_id ||
  `trace_${now}_${Math.random().toString(36).slice(2, 10)}`;

const answer = `ขอพักสัก ${retrySeconds} วินาทีครับ แล้วลองถามใหม่อีกครั้งครับ`;

const frontend_response = {
  answer,
  kb_relevance: 0,
  confidence: 0,
  doc_id: "rate_limited",
  escalate: false,
  escalate_reason: "",
  model: "rate_limit",
  trace_id,
};

return [
  {
    json: {
      ...frontend_response,
      frontend_response,
      sheet_log_payload: {
        timestamp: input.timestamp || new Date(now).toISOString(),
        trace_id,
        session_id: input.session_id || "",
        student_id: input.student_id || "",
        course_id: input.course_id || "",
        nickname: input.nickname || "",
        question: input.message || "",
        answer,
        response_time_ms: 0,
        kb_relevance: 0,
        confidence: 0,
        doc_id: "rate_limited",
        model: "rate_limit",
        escalated: false,
        escalate_reason: "",
        citation_parse_failed: false,
        fallback_used: false,
        primary_error: "",
        model_strategy: "guard",
        model_selection_reason: "Rate limit guard blocked the request before model routing.",
        safety_critical: false,
        usage_prompt_tokens: null,
        usage_completion_tokens: null,
        usage_total_tokens: null,
        response_cost: null,
        feedback_type: "rate_limited",
      },
    },
  },
];

const input = $input.first().json;
const text = String(input.message || "").toLowerCase();
const history = Array.isArray(input.history) ? input.history : [];

const MODELS = {
  fastLite: "google/gemini-2.5-flash-lite",
  fast: "google/gemini-2.5-flash",
  quality: "openai/gpt-5.5",
  safety: "anthropic/claude-sonnet-4.6",
};

function hasAny(words) {
  return words.some((word) => text.includes(word));
}

const injectionKeywords = [
