  "\u0e27\u0e34\u0e40\u0e04\u0e23\u0e32\u0e30\u0e2b\u0e4c",
  "\u0e40\u0e1b\u0e23\u0e35\u0e22\u0e1a\u0e40\u0e17\u0e35\u0e22\u0e1a",
  "\u0e2b\u0e25\u0e32\u0e22\u0e02\u0e31\u0e49\u0e19",
  "\u0e17\u0e33\u0e22\u0e31\u0e07\u0e44\u0e07\u0e15\u0e48\u0e2d",
  "\u0e22\u0e31\u0e07\u0e44\u0e21\u0e48\u0e41\u0e19\u0e48\u0e43\u0e08",
  "edge case",
];

const hasInjectionRisk = hasAny(injectionKeywords);
const isSafetyCritical = hasAny(safetyKeywords) || /\d+\s*(mm|\u0e21\u0e21|\u0e0a\u0e31\u0e48\u0e27\u0e42\u0e21\u0e07|%)/i.test(text);
const isSimple = text.length <= 90 && history.length === 0 && hasAny(simpleKeywords) && !isSafetyCritical && !hasInjectionRisk;
const isComplex = history.length > 0 || text.length > 240 || hasAny(complexKeywords);

let model_strategy = "standard_fast";
let primary_model = MODELS.fast;
let fallback_model = MODELS.quality;
let model_selection_reason = "Default KB tutor route; use Gemini 2.5 Flash for speed/cost, fallback to GPT-5.5 for answer quality.";

if (hasInjectionRisk) {
  model_strategy = "security_guard";
  primary_model = MODELS.quality;
  fallback_model = MODELS.safety;
  model_selection_reason = "Prompt-injection or instruction override pattern detected; use strongest guard-capable model first.";
} else if (isSafetyCritical) {
  model_strategy = "safety_quality";
  primary_model = MODELS.safety;
  fallback_model = MODELS.quality;
  model_selection_reason = "Safety, numerical, specification, approval, or design-conflict keyword detected; prefer safety-quality model first.";
} else if (isComplex) {
  model_strategy = "complex_quality";
  primary_model = MODELS.quality;
  fallback_model = MODELS.safety;
  model_selection_reason = "Multi-turn, long, or analytical scenario; use highest-quality model first.";
} else if (isSimple) {
  model_strategy = "simple_fast";
  primary_model = MODELS.fastLite;
  fallback_model = MODELS.quality;
  model_selection_reason = "Short low-risk definition/navigation question; use cheapest low-latency model first.";
}

return [
  {
    json: {
      ...input,
      model_strategy,
      model_selection_reason,
      safety_critical: isSafetyCritical,
      prompt_injection_risk: hasInjectionRisk,
      primary_model,
      fallback_model,
    },
  },
];
